'use client';

import Image from "next/image";
import Link from "next/link";

const navLinks = [
  { label: "Servicios",      href: "#services" },
  { label: "Trabajos",       href: "#portfolio" },
  { label: "Nosotros",       href: "#stats" },
  { label: "Testimonios",   href: "#testimonials" },
  { label: "Contacto",       href: "#contact" },
];

const serviceLinks = [
  { label: "Desarrollo Web",       href: "#services" },
  { label: "Contenido Audiovisual", href: "#services" },
  { label: "Fotografía",           href: "#services" },
  { label: "Campañas de Marketing", href: "#services" },
];

const legalLinks = [
  { label: "Política de Privacidad", href: "#" },
  { label: "Términos de Servicio",   href: "#" },
  { label: "Política de Cookies",    href: "#" },
];

const socialLinks = [
  {
    label: "X (Twitter)",
    href: "https://x.com",
    icon: (
      <svg
        viewBox="0 0 24 24"
        fill="currentColor"
        xmlns="http://www.w3.org/2000/svg"
        className="w-5 h-5"
        aria-hidden="true"
      >
        <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-4.714-6.231-5.401 6.231H2.744l7.737-8.835L1.254 2.25H8.08l4.253 5.622 5.91-5.622zm-1.161 17.52h1.833L7.084 4.126H5.117L17.083 19.77z" />
      </svg>
    ),
  },
  {
    label: "Instagram",
    href: "https://instagram.com",
    icon: (
      <svg
        viewBox="0 0 24 24"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        className="w-5 h-5"
        aria-hidden="true"
      >
        <rect x="2" y="2" width="20" height="20" rx="5" stroke="currentColor" strokeWidth="1.8" />
        <circle cx="12" cy="12" r="4.5" stroke="currentColor" strokeWidth="1.8" />
        <circle cx="17.5" cy="6.5" r="1" fill="currentColor" />
      </svg>
    ),
  },
  {
    label: "LinkedIn",
    href: "https://linkedin.com",
    icon: (
      <svg
        viewBox="0 0 24 24"
        fill="currentColor"
        xmlns="http://www.w3.org/2000/svg"
        className="w-5 h-5"
        aria-hidden="true"
      >
        <path d="M16 8a6 6 0 016 6v7h-4v-7a2 2 0 00-2-2 2 2 0 00-2 2v7h-4v-7a6 6 0 016-6zM2 9h4v12H2z" />
        <circle cx="4" cy="4" r="2" />
      </svg>
    ),
  },
];

function handleScrollTo(href: string) {
  const id = href.replace("#", "");
  const el = document.getElementById(id);
  if (el) el.scrollIntoView({ behavior: "smooth" });
}

export default function Footer() {
  const year = new Date().getFullYear();

  return (
    <footer className="" role="contentinfo" style={{ backgroundColor: "var(--color-bg)" }}>
      {/* Top border in brand-subtle */}
      <div className="h-px w-full" style={{ backgroundColor: "var(--color-brand-red-bg)" }} />

      {/* ── Upper footer ────────────────────────────────────────── */}
      <div className="max-w-7xl mx-auto px-6 lg:px-8 pt-16 pb-12">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10 lg:gap-8">

          {/* Column 1 — Brand + tagline */}
          <div className="lg:col-span-1">
            {/* Logo */}
            <button
              onClick={() => window.scrollTo({ top: 0, behavior: "smooth" })}
              className="flex items-center mb-5 group"
              aria-label="Volver al inicio"
            >
              <Image
                src="/logos/transparente.png"
                alt="ReckTrack Marketing Digital"
                width={160}
                height={48}
                className="h-10 w-auto object-contain"
              />
            </button>

            {/* Tagline */}
            <p
              className="mb-6 leading-relaxed"
              style={{
                fontFamily: "var(--font-body)",
                fontSize: "0.9rem",
                fontWeight: 400,
                color: "var(--color-muted)",
                lineHeight: 1.7,
                fontStyle: "italic",
              }}
            >
              &ldquo;No solo hacemos marketing&nbsp;— construimos marcas que
              se mueven.&rdquo;
            </p>

            {/* Social icons */}
            <div className="flex items-center gap-3" role="list" aria-label="Social media links">
              {socialLinks.map((social) => (
                <a
                  key={social.label}
                  href={social.href}
                  target="_blank"
                  rel="noopener noreferrer"
                  aria-label={social.label}
                  role="listitem"
                  className="w-10 h-10 rounded-lg flex items-center justify-center transition-all duration-300 hover:-translate-y-0.5 hover:shadow-md"
                  style={{
                    backgroundColor: "var(--color-raised)",
                    color: "var(--color-muted)",
                  }}
                  onMouseEnter={(e) => {
                    (e.currentTarget as HTMLAnchorElement).style.backgroundColor = "var(--color-brand-primary)";
                    (e.currentTarget as HTMLAnchorElement).style.color = "var(--color-text)";
                  }}
                  onMouseLeave={(e) => {
                    (e.currentTarget as HTMLAnchorElement).style.backgroundColor = "var(--color-raised)";
                    (e.currentTarget as HTMLAnchorElement).style.color = "var(--color-muted)";
                  }}
                >
                  {social.icon}
                </a>
              ))}
            </div>
          </div>

          {/* Column 2 — Navigation */}
          <div>
            <h3
              className="mb-5 uppercase tracking-widest text-xs"
              style={{
                fontFamily: "var(--font-display)",
                fontWeight: 700,
                color: "var(--color-text)",
                letterSpacing: "0.14em",
                fontSize: "0.7rem",
              }}
            >
              Navegar
            </h3>
            <ul className="flex flex-col gap-3" role="list">
              {navLinks.map((link) => (
                <li key={link.href}>
                  <button
                    onClick={() => handleScrollTo(link.href)}
                    className="nav-link text-sm transition-colors duration-300 hover:text-brand-primary"
                    style={{
                      fontFamily: "var(--font-body)",
                      fontWeight: 400,
                      color: "var(--color-muted)",
                      fontSize: "0.9rem",
                    }}
                  >
                    {link.label}
                  </button>
                </li>
              ))}
            </ul>
          </div>

          {/* Column 3 — Services */}
          <div>
            <h3
              className="mb-5 uppercase tracking-widest text-xs"
              style={{
                fontFamily: "var(--font-display)",
                fontWeight: 700,
                color: "var(--color-text)",
                letterSpacing: "0.14em",
                fontSize: "0.7rem",
              }}
            >
              Servicios
            </h3>
            <ul className="flex flex-col gap-3" role="list">
              {serviceLinks.map((link) => (
                <li key={link.label}>
                  <button
                    onClick={() => handleScrollTo(link.href)}
                    className="nav-link text-sm transition-colors duration-300 hover:text-brand-primary"
                    style={{
                      fontFamily: "var(--font-body)",
                      fontWeight: 400,
                      color: "var(--color-muted)",
                      fontSize: "0.9rem",
                    }}
                  >
                    {link.label}
                  </button>
                </li>
              ))}
            </ul>
          </div>

          {/* Column 4 — CTA card */}
          <div>
            <div
              className="rounded-2xl p-6 relative overflow-hidden"
              style={{ backgroundColor: "var(--color-brand-red-bg)" }}
            >
              {/* Decorative circle */}
              <div
                className="absolute -bottom-6 -right-6 w-24 h-24 rounded-full opacity-30"
                style={{ backgroundColor: "#D32F2F" }}
                aria-hidden="true"
              />

              <h3
                className="mb-2 relative z-10"
                style={{
                  fontFamily: "var(--font-display)",
                  fontWeight: 700,
                  fontSize: "1rem",
                  color: "var(--color-text)",
                  lineHeight: 1.3,
                }}
              >
                Iniciar un proyecto con nosotros
              </h3>
              <p
                className="mb-5 relative z-10"
                style={{
                  fontFamily: "var(--font-body)",
                  fontSize: "0.82rem",
                  fontWeight: 400,
                  color: "var(--color-muted)",
                  lineHeight: 1.6,
                }}
              >
                Desde la estrategia hasta el lanzamiento, estamos listos para
                construir algo extraordinario juntos.
              </p>
              <button
                onClick={() => handleScrollTo("#contact")}
                className="relative z-10 w-full btn-primary text-sm py-2.5"
                style={{ fontFamily: "var(--font-display)", fontWeight: 600, fontSize: "0.875rem" }}
              >
                Solicitar Cotización Gratis
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* ── Divider ─────────────────────────────────────────────── */}
      <div className="max-w-7xl mx-auto px-6 lg:px-8">
        <div className="h-px w-full" style={{ backgroundColor: "var(--color-border)" }} />
      </div>

      {/* ── Lower footer ────────────────────────────────────────── */}
      <div className="max-w-7xl mx-auto px-6 lg:px-8 py-6">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4">

          {/* Copyright */}
          <p
            style={{
              fontFamily: "var(--font-body)",
              fontSize: "0.8rem",
              fontWeight: 400,
              color: "var(--color-dim)",
            }}
          >
            &copy; {year} ReckTrack Marketing Digital. Todos los derechos reservados.
          </p>

          {/* Legal links */}
          <div className="flex items-center gap-1" role="list" aria-label="Legal links">
            {legalLinks.map((link, i) => (
              <span key={link.label} className="flex items-center" role="listitem">
                {i > 0 && (
                  <span
                    className="mx-2"
                    style={{ color: "var(--color-border)" }}
                    aria-hidden="true"
                  >
                    ·
                  </span>
                )}
                <Link
                  href={link.href}
                  className="transition-colors duration-300 hover:text-brand-primary"
                  style={{
                    fontFamily: "var(--font-body)",
                    fontSize: "0.8rem",
                    fontWeight: 400,
                    color: "var(--color-dim)",
                  }}
                >
                  {link.label}
                </Link>
              </span>
            ))}
          </div>

          {/* Crafted with badge */}
          <div className="flex items-center gap-1.5">
            <span
              style={{
                fontFamily: "var(--font-body)",
                fontSize: "0.75rem",
                fontWeight: 400,
                color: "var(--color-dim)",
              }}
            >
              Hecho con
            </span>
            <svg
              viewBox="0 0 14 14"
              fill="#B71C1C"
              xmlns="http://www.w3.org/2000/svg"
              className="w-3.5 h-3.5"
              aria-label="love"
            >
              <path d="M7 12.5S1 8.5 1 4.5A3 3 0 017 3a3 3 0 016 1.5C13 8.5 7 12.5 7 12.5z" />
            </svg>
            <span
              style={{
                fontFamily: "var(--font-body)",
                fontSize: "0.75rem",
                fontWeight: 400,
                color: "var(--color-dim)",
              }}
            >
              por ReckTrack MD
            </span>
          </div>
        </div>
      </div>
    </footer>
  );
}
