'use client';

import { useEffect, useState } from "react";

const headline = ["Construimos", "Marcas", "que", "se", "Mueven."];

export default function Hero() {
  const [mounted, setMounted] = useState(false);

  useEffect(() => { setMounted(true); }, []);

  const handleScrollTo = (id: string) => {
    document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <section
      id="hero"
      className="relative h-screen flex items-center overflow-hidden"
      style={{ backgroundColor: "var(--color-bg)" }}
    >
      {/* ── Background: large red gradient wash ─────────────────── */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          background: "radial-gradient(ellipse 80% 70% at 70% 50%, rgba(183,28,28,0.10) 0%, transparent 70%)",
        }}
        aria-hidden="true"
      />

      {/* Subtle noise texture via repeating gradient */}
      <div
        className="absolute inset-0 pointer-events-none opacity-[0.03]"
        style={{
          backgroundImage: "url(\"data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E\")",
          backgroundSize: "200px 200px",
        }}
        aria-hidden="true"
      />

      {/* Animated blob — bottom left */}
      <div
        className="absolute -bottom-40 -left-32 w-[500px] h-[500px] rounded-full pointer-events-none"
        style={{
          background: "radial-gradient(circle, rgba(127,0,0,0.08) 0%, transparent 70%)",
          animationName:           mounted ? "floatBlob" : "none",
          animationDuration:       "15s",
          animationTimingFunction: "ease-in-out",
          animationIterationCount: "infinite",
          animationDirection:      "reverse",
          animationDelay:          "3s",
          animationFillMode:       "both",
        }}
        aria-hidden="true"
      />


      {/* ── Main content ──────────────────────────────────────────── */}
      <div className="relative z-10 max-w-7xl mx-auto px-6 lg:px-8 w-full pt-16">
        <div className="grid grid-cols-1 lg:grid-cols-[1fr_420px] gap-16 items-center min-h-[calc(100vh-4rem)]">

          {/* ── Left: copy ────────────────────────────────────────── */}
          <div className="flex flex-col justify-center py-12">

            {/* Eyebrow pill */}
            <div
              className="inline-flex items-center gap-2 mb-8 self-start"
              style={{
                opacity: mounted ? 1 : 0,
                transform: mounted ? "translateY(0)" : "translateY(12px)",
                transition: "opacity 0.5s ease 0.1s, transform 0.5s ease 0.1s",
              }}
            >
              <span
                className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full border"
                style={{
                  borderColor: "var(--color-brand-red-border)",
                  backgroundColor: "var(--color-brand-red-bg)",
                }}
              >
                <span
                  className="w-1.5 h-1.5 rounded-full"
                  style={{ backgroundColor: "#B71C1C", boxShadow: "0 0 6px #B71C1C" }}
                />
                <span
                  style={{
                    fontFamily: "var(--font-body)",
                    fontWeight: 500,
                    fontSize: "0.68rem",
                    color: "var(--color-brand-light)",
                    letterSpacing: "0.18em",
                    textTransform: "uppercase",
                  }}
                >
                  Agencia Digital Integral
                </span>
              </span>
            </div>

            {/* Headline */}
            <h1
              className="font-display mb-7"
              style={{
                fontFamily: "var(--font-display)",
                fontSize: "clamp(3.2rem, 5.5vw, 5.75rem)",
                fontWeight: 800,
                color: "var(--color-text)",
                lineHeight: 1.0,
                letterSpacing: "-0.03em",
              }}
            >
              {headline.map((word, i) => (
                <span
                  key={i}
                  className="inline-block mr-[0.2em] last:mr-0"
                  style={
                    mounted
                      ? { animation: "fadeUp 0.6s ease forwards", animationDelay: `${0.2 + i * 0.1}s`, opacity: 0 }
                      : { opacity: 0 }
                  }
                >
                  {word === "Mueven." ? (
                    <span style={{ color: "var(--color-brand-glow)" }}>{word}</span>
                  ) : word}
                </span>
              ))}
            </h1>

            {/* Subheadline */}
            <p
              className="font-body mb-10"
              style={{
                fontFamily: "var(--font-body)",
                fontSize: "clamp(1rem, 1.3vw, 1.1rem)",
                fontWeight: 400,
                color: "var(--color-muted)",
                lineHeight: 1.75,
                maxWidth: "32rem",
                opacity: mounted ? 1 : 0,
                transform: mounted ? "translateY(0)" : "translateY(16px)",
                transition: "opacity 0.6s ease 0.75s, transform 0.6s ease 0.75s",
              }}
            >
              ReckTrack MD combina estrategia, tecnología y creatividad para
              construir marcas digitales que destacan y generan resultados reales.
            </p>

            {/* CTAs */}
            <div
              className="flex flex-wrap gap-4 items-center mb-14"
              style={{
                opacity: mounted ? 1 : 0,
                transform: mounted ? "translateY(0)" : "translateY(16px)",
                transition: "opacity 0.6s ease 0.95s, transform 0.6s ease 0.95s",
              }}
            >
              <button
                onClick={() => handleScrollTo("contact")}
                className="inline-flex items-center gap-2 px-7 py-3.5 rounded-xl font-display font-700 text-white transition-all duration-300 hover:-translate-y-0.5 hover:shadow-lg"
                style={{
                  fontFamily: "var(--font-display)",
                  fontWeight: 700,
                  fontSize: "0.95rem",
                  background: "linear-gradient(135deg, #B71C1C 0%, #7F0000 100%)",
                  boxShadow: "0 4px 24px rgba(183,28,28,0.4)",
                }}
              >
                Iniciar Proyecto
                <svg className="w-4 h-4" viewBox="0 0 16 16" fill="none" aria-hidden="true">
                  <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </button>
              <button
                onClick={() => handleScrollTo("portfolio")}
                className="inline-flex items-center gap-2 px-7 py-3.5 rounded-xl font-display font-700 transition-all duration-300 hover:-translate-y-0.5"
                style={{
                  fontFamily: "var(--font-display)",
                  fontWeight: 600,
                  fontSize: "0.95rem",
                  color: "var(--color-muted)",
                  border: "1px solid var(--color-border-soft)",
                  backgroundColor: "var(--color-faint)",
                }}
              >
                Ver Nuestro Trabajo
              </button>
            </div>

            {/* Trust bar */}
            <div
              className="flex flex-wrap gap-8 pt-7 border-t"
              style={{
                borderColor: "rgba(255,255,255,0.08)",
                opacity: mounted ? 1 : 0,
                transition: "opacity 0.6s ease 1.2s",
              }}
            >
              {[
                {
                  icon: <svg viewBox="0 0 20 20" fill="none" className="w-4 h-4"><circle cx="7" cy="6" r="2.5" stroke="var(--color-brand-glow)" strokeWidth="1.6"/><path d="M1 17c0-3 2.5-5 6-5" stroke="var(--color-brand-glow)" strokeWidth="1.6" strokeLinecap="round"/><circle cx="13" cy="6" r="2.5" stroke="var(--color-brand-glow)" strokeWidth="1.6"/><path d="M13 12c3.5 0 6 2 6 5" stroke="var(--color-brand-glow)" strokeWidth="1.6" strokeLinecap="round"/></svg>,
                  value: "50+", label: "Clientes"
                },
                {
                  icon: <svg viewBox="0 0 20 20" fill="none" className="w-4 h-4"><rect x="2" y="4" width="16" height="13" rx="2" stroke="var(--color-brand-glow)" strokeWidth="1.6"/><path d="M6 2v4M14 2v4M2 9h16" stroke="var(--color-brand-glow)" strokeWidth="1.6" strokeLinecap="round"/></svg>,
                  value: "8+", label: "Años"
                },
                {
                  icon: <svg viewBox="0 0 20 20" fill="none" className="w-4 h-4"><path d="M10 2l2 4.9 5.4.8-3.9 3.8.9 5.3L10 14.2l-4.8 2.6.9-5.3L2.2 7.7l5.4-.8L10 2z" stroke="var(--color-brand-glow)" strokeWidth="1.6" strokeLinejoin="round"/></svg>,
                  value: "4", label: "Servicios"
                },
                {
                  icon: <svg viewBox="0 0 20 20" fill="none" className="w-4 h-4"><circle cx="10" cy="10" r="8" stroke="var(--color-brand-glow)" strokeWidth="1.6"/><path d="M7 12.5s1.2 1.5 3 1.5 3-1.5 3-1.5" stroke="var(--color-brand-glow)" strokeWidth="1.6" strokeLinecap="round"/><circle cx="7.5" cy="8.5" r="1" fill="var(--color-brand-glow)"/><circle cx="12.5" cy="8.5" r="1" fill="var(--color-brand-glow)"/></svg>,
                  value: "100%", label: "Satisfacción"
                },
              ].map((s) => (
                <div key={s.label} className="flex items-center gap-2.5">
                  <div className="flex-shrink-0">{s.icon}</div>
                  <div>
                    <div className="font-display font-800 leading-none" style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: "1.35rem", color: "var(--color-text)" }}>{s.value}</div>
                    <div className="font-body uppercase tracking-widest mt-0.5" style={{ fontFamily: "var(--font-body)", fontWeight: 500, color: "var(--color-dim)", letterSpacing: "0.1em", fontSize: "0.6rem" }}>{s.label}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* ── Right: visual panel ────────────────────────────────── */}
          <div
            className="hidden lg:block"
            style={{
              opacity: mounted ? 1 : 0,
              transform: mounted ? "translateY(0)" : "translateY(32px)",
              transition: "opacity 0.9s ease 0.5s, transform 0.9s ease 0.5s",
            }}
          >
            <div className="relative">

              {/* Main dark card */}
              <div
                className="relative rounded-3xl overflow-hidden"
                style={{
                  background: "var(--color-surface)",
                  border: "1px solid var(--color-border)",
                  boxShadow: "0 8px 40px rgba(0,0,0,0.10), 0 0 0 3px rgba(183,28,28,0.07)",
                }}
              >
                {/* Card header bar */}
                <div className="flex items-center gap-1.5 px-6 py-4 border-b" style={{ borderColor: "var(--color-border)" }}>
                  <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: "var(--color-brand-glow)" }} />
                  <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: "var(--color-faint)" }} />
                  <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: "var(--color-faint)" }} />
                  <span className="ml-3 font-body text-xs" style={{ fontFamily: "var(--font-body)", color: "var(--color-faint)", fontSize: "0.7rem", letterSpacing: "0.05em" }}>
                    recktrack.com
                  </span>
                </div>

                <div className="p-7">
                  {/* Section label */}
                  <p className="font-body mb-5" style={{ fontFamily: "var(--font-body)", fontSize: "0.62rem", fontWeight: 600, color: "var(--color-dim)", letterSpacing: "0.15em", textTransform: "uppercase" }}>
                    Cómo trabajamos
                  </p>

                  {/* Process steps */}
                  <div className="flex flex-col gap-3 mb-6">
                    {[
                      {
                        step: "01",
                        title: "Consulta Inicial",
                        desc: "Entendemos tu marca, objetivos y audiencia target.",
                        icon: (
                          <svg viewBox="0 0 20 20" fill="none" className="w-4 h-4 flex-shrink-0" aria-hidden="true">
                            <circle cx="10" cy="10" r="7.5" stroke="var(--color-brand-glow)" strokeWidth="1.5"/>
                            <path d="M10 6v4.5l3 1.5" stroke="var(--color-brand-glow)" strokeWidth="1.5" strokeLinecap="round"/>
                          </svg>
                        ),
                      },
                      {
                        step: "02",
                        title: "Estrategia",
                        desc: "Diseñamos un plan personalizado para tu negocio.",
                        icon: (
                          <svg viewBox="0 0 20 20" fill="none" className="w-4 h-4 flex-shrink-0" aria-hidden="true">
                            <path d="M3 15l4-4 3 3 4-5 3 3" stroke="var(--color-brand-glow)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                            <circle cx="3" cy="15" r="1" fill="var(--color-brand-glow)"/>
                            <circle cx="17" cy="12" r="1" fill="var(--color-brand-glow)"/>
                          </svg>
                        ),
                      },
                      {
                        step: "03",
                        title: "Creación",
                        desc: "Producimos contenido y soluciones de alto impacto.",
                        icon: (
                          <svg viewBox="0 0 20 20" fill="none" className="w-4 h-4 flex-shrink-0" aria-hidden="true">
                            <path d="M4 14l3-3 2.5 2.5L14 8l2 2" stroke="var(--color-brand-glow)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                            <rect x="2.5" y="3.5" width="15" height="13" rx="1.5" stroke="var(--color-brand-glow)" strokeWidth="1.5"/>
                          </svg>
                        ),
                      },
                      {
                        step: "04",
                        title: "Lanzamiento",
                        desc: "Publicamos, medimos y optimizamos resultados.",
                        icon: (
                          <svg viewBox="0 0 20 20" fill="none" className="w-4 h-4 flex-shrink-0" aria-hidden="true">
                            <path d="M10 2.5c0 0 5.5 2 6 8.5s-5 7-6 7-6-1.5-6-7 6-8.5 6-8.5z" stroke="var(--color-brand-glow)" strokeWidth="1.5" strokeLinejoin="round"/>
                            <path d="M10 2.5v14M4.5 8h11" stroke="var(--color-brand-glow)" strokeWidth="1.5" strokeLinecap="round"/>
                          </svg>
                        ),
                      },
                    ].map((item, i) => (
                      <div
                        key={item.step}
                        className="flex items-start gap-3 rounded-xl px-4 py-3"
                        style={{ backgroundColor: "var(--color-faint)", border: "1px solid var(--color-border)" }}
                      >
                        {/* Step number */}
                        <div
                          className="flex-shrink-0 w-6 h-6 rounded-md flex items-center justify-center mt-0.5"
                          style={{ backgroundColor: "var(--color-brand-red-bg)", border: "1px solid var(--color-brand-red-border)" }}
                        >
                          <span className="font-display" style={{ fontFamily: "var(--font-display)", fontSize: "0.55rem", fontWeight: 800, color: "var(--color-brand-glow)", letterSpacing: "0.05em" }}>
                            {item.step}
                          </span>
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 mb-0.5">
                            {item.icon}
                            <span className="font-display" style={{ fontFamily: "var(--font-display)", fontSize: "0.78rem", fontWeight: 700, color: "var(--color-text)" }}>
                              {item.title}
                            </span>
                          </div>
                          <p className="font-body" style={{ fontFamily: "var(--font-body)", fontSize: "0.68rem", fontWeight: 400, color: "var(--color-muted)", lineHeight: 1.5 }}>
                            {item.desc}
                          </p>
                        </div>
                      </div>
                    ))}
                  </div>

                  {/* CTA */}
                  <button
                    onClick={() => document.getElementById("services")?.scrollIntoView({ behavior: "smooth" })}
                    className="w-full flex items-center justify-between rounded-xl px-4 py-3 transition-all duration-300 hover:opacity-85"
                    style={{ background: "linear-gradient(135deg, #B71C1C 0%, #7F0000 100%)" }}
                  >
                    <span className="font-display" style={{ fontFamily: "var(--font-display)", fontSize: "0.82rem", fontWeight: 700, color: "#fff" }}>
                      Ver todos los servicios
                    </span>
                    <svg viewBox="0 0 16 16" fill="none" className="w-4 h-4 flex-shrink-0" aria-hidden="true">
                      <path d="M3 8h10M9 4l4 4-4 4" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                    </svg>
                  </button>
                </div>
              </div>

              {/* Floating "Disponible" badge — top right */}
              <div
                className="absolute -top-4 -right-4 rounded-xl px-3 py-2 flex items-center gap-2"
                style={{
                  background: "var(--color-brand-red-bg)",
                  border: "1px solid var(--color-brand-red-border)",
                  backdropFilter: "blur(8px)",
                }}
              >
                <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: "var(--color-brand-glow)", boxShadow: "0 0 6px var(--color-brand-glow)", animation: mounted ? "floatBlob 1.5s ease-in-out infinite" : "none" }} />
                <span className="font-body" style={{ fontFamily: "var(--font-body)", fontSize: "0.65rem", fontWeight: 600, color: "var(--color-brand-light)", letterSpacing: "0.1em", textTransform: "uppercase" }}>
                  Disponible
                </span>
              </div>

            </div>
          </div>

        </div>
      </div>
    </section>
  );
}
